arguments.argument:
if global.gamePaused=false
{
  if type=6
  {
    if activated=1
    {
      timeLeft-=1
      if timeLeft<=0
      {
        activated=0
        timeLeft=15
      }
    }
  }
}

if instance_exists(ownerID)
{
  /*
